  function gcd(a, b) {
    while (b) { [a, b] = [b, a % b]; }
    return a;
  }
)};

const _mmi = function mmi(gcd){return(
  function mmi(a, m) {
    for (let x = 1; x < m; x++) {
      if ((a * x) % m === 1) return x;
    }
    return -1;
  }
)};

const _encode = function encode(gcd){return(
  function encode(phrase, key) {
    const { a, b } = key;
    const m = 26;
    if (gcd(a, m) !== 1) throw new Error("a and m must be coprime");
    let out = "";
    for (const ch of phrase.toLowerCase()) {
      if (ch >= "a" && ch <= "z") {
        const i = ch.charCodeAt(0) - 97;
        out += String.fromCharCode(((a * i + b) % m) + 97);
      } else if (ch >= "0" && ch <= "9") {
        out += ch;
      }
      // skip spaces and punctuation
    }
    // group into chunks of 5
    return out.match(/.{1,5}/g)?.join(" ") ?? "";
  }
)};

const _decode = function decode(gcd, mmi){return(
  function decode(ciphertext, key) {
    const { a, b } = key;
    const m = 26;
    if (gcd(a, m) !== 1) throw new Error("a and m must be coprime");
    const aInv = mmi(a, m);
    let out = "";
    for (const ch of ciphertext.toLowerCase()) {
      if (ch >= "a" && ch <= "z") {
        const y = ch.charCodeAt(0) - 97;
        out += String.fromCharCode((((aInv * (y - b)) % m + m) % m) + 97);
      } else if (ch >= "0" && ch <= "9") {
        out += ch;
      }
      // skip spaces (grouping) and punctuation
    }
    return out;
  }
