const _solve = function solve(){
  return (puzzle) => {
    // Parse the puzzle
    const [left, right] = puzzle.split('=').map(s => s.trim());
    const addends = left.split('+').map(s => s.trim());
    const result = right.trim();
    const words = [...addends, result];

    // Get all unique letters
    const letters = [...new Set(words.join('').split(''))];
    const n = letters.length;
    if (n > 10) return null;

    // Leading letters cannot be zero
    const leadingSet = new Set(words.map(w => w[0]));

    // Map each letter to its index
    const idx = {};
    letters.forEach((c, i) => idx[c] = i);

    // Assign letters column-by-column (right to left) for better pruning
    const maxLen = Math.max(...words.map(w => w.length));
    const letterOrder = [];
    const seen = new Set();
    for (let col = 0; col < maxLen; col++) {
      for (const w of words) {
        const ci = w.length - 1 - col;
        if (ci >= 0 && !seen.has(w[ci])) {
          seen.add(w[ci]);
          letterOrder.push(w[ci]);
        }
      }
    }
    // Add any remaining letters (safety)
    for (const c of letters) {
      if (!seen.has(c)) { seen.add(c); letterOrder.push(c); }
    }

    // Pre-compute digit-position weights for each word
    const wordWeights = words.map(w => {
      const chars = [...w];
      return chars.map((_, i) => Math.pow(10, chars.length - 1 - i));
    });

    const assignment = new Array(n);
    const used = new Array(10).fill(false);

    // Evaluate a word given current assignment
    const evalWord = (wordIdx) => {
      let sum = 0;
      const weights = wordWeights[wordIdx];
      const word = words[wordIdx];
      for (let i = 0; i < word.length; i++) {
        sum += assignment[idx[word[i]]] * weights[i];
      }
      return sum;
    };

    // Backtracking search
    const solveBT = (pos) => {
      if (pos === n) {
        const addendSum = addends.reduce((s, _, wi) => s + evalWord(wi), 0);
        const resultNum = evalWord(addends.length);
        if (addendSum === resultNum) {
          const solution = {};
          letters.forEach((c, i) => solution[c] = assignment[i]);
          return solution;
        }
        return null;
      }

      const letter = letterOrder[pos];
      const li = idx[letter];
      const start = leadingSet.has(letter) ? 1 : 0;

      for (let d = start; d <= 9; d++) {
        if (used[d]) continue;
        used[d] = true;
        assignment[li] = d;
        const res = solveBT(pos + 1);
        if (res) return res;
        used[d] = false;
        assignment[li] = undefined;
      }
      return null;
    };

    return solveBT(0);
  };
};

