const _cost = function cost() {
  return function calculateCost(books) {
    if (!books || books.length === 0) return 0;
    // Count copies of each book (books are 0-indexed identifiers)
    const counts = [0, 0, 0, 0, 0];
    for (const book of books) {
      counts[book]++;
    }
    // Form groups greedily: each group takes one copy of each available distinct book
    const groups = [];
    while (counts.some(c => c > 0)) {
      let groupSize = 0;
      for (let i = 0; i < 5; i++) {
        if (counts[i] > 0) {
          counts[i]--;
          groupSize++;
        }
      }
      if (groupSize > 0) groups.push(groupSize);
    }
    // Optimize: a 5-group + 3-group is more expensive than two 4-groups
    while (groups.includes(5) && groups.includes(3)) {
      groups[groups.indexOf(5)] = 4;
      groups[groups.indexOf(3)] = 4;
    }
    // Price per group size in cents
    const prices = { 1: 800, 2: 1520, 3: 2160, 4: 2560, 5: 3000 };
    let total = 0;
    for (const g of groups) {
      total += prices[g];
    }
    return total;
  };
};

