const _clean = function clean(){
  return function clean(input) {
    // Remove all non-digit characters
    const digits = input.replace(/\D/g, '');

    // Check for letters in original input
    if (/[a-zA-Z]/.test(input)) {
      throw new Error('Letters not permitted');
    }

    // Check for invalid punctuation (@, !, etc.)
    if (/[@:!]/.test(input)) {
      throw new Error('Punctuations not permitted');
    }

    // Determine if country code is present
    let number;
    if (digits.length === 11) {
      if (digits[0] !== '1') {
        throw new Error('11 digits must start with 1');
      }
      number = digits.slice(1);
    } else if (digits.length === 10) {
      number = digits;
    } else if (digits.length < 10) {
      throw new Error('Incorrect number of digits');
    } else {
      throw new Error('More than 11 digits');
    }

    // Validate area code (first digit must be 2-9)
    if (number[0] < '2' || number[0] > '9') {
      throw new Error('Area code cannot start with ' + (number[0] === '0' ? 'zero' : 'one'));
    }

    // Validate exchange code (fourth digit must be 2-9)
    if (number[3] < '2' || number[3] > '9') {
      throw new Error('Exchange code cannot start with ' + (number[3] === '0' ? 'zero' : 'one'));
    }

    return number;
  };
};

